using System.ComponentModel;
using Microsoft.Extensions.AI;
using OpenAI;

// --- Tool implementations ---

var notebook = new Notebook();

var searchTool = AIFunctionFactory.Create(
    (string query) =>
    {
        Console.WriteLine($"  🔍 Searching: \"{query}\"");
        return WebSearcher.SearchAsync(query);
    },
    "web_search",
    "Searches the web for information on a given query and returns a list of result snippets.");

var addNoteTool = AIFunctionFactory.Create(
    ([Description("A concise note capturing a key finding")] string note) =>
    {
        notebook.Add(note);
        Console.WriteLine($"  📝 Noted: {note[..Math.Min(note.Length, 80)]}...");
        return "Note saved.";
    },
    "add_note",
    "Saves an important finding or fact to the notebook for later summarization.");

var readNotesTool = AIFunctionFactory.Create(
    () =>
    {
        var notes = notebook.GetAll();
        return notes.Count == 0
            ? "No notes yet."
            : string.Join("\n", notes.Select((n, i) => $"{i + 1}. {n}"));
    },
    "read_notes",
    "Reads all notes collected so far.");

// --- Agent setup ---

var apiKey = Environment.GetEnvironmentVariable("OPENAI_API_KEY")
    ?? throw new InvalidOperationException(
        "Set the OPENAI_API_KEY environment variable to run this agent.");

var model = Environment.GetEnvironmentVariable("OPENAI_MODEL") ?? "gpt-4o-mini";

IChatClient client = new OpenAIClient(apiKey)
    .GetChatClient(model)
    .AsIChatClient();

var chatOptions = new ChatOptions
{
    Tools = [searchTool, addNoteTool, readNotesTool],
    ToolMode = ChatToolMode.Auto
};

var topic = args.Length > 0
    ? string.Join(' ', args)
    : PromptForTopic();

Console.WriteLine($"\n🤖 Research Agent Starting — topic: \"{topic}\"\n");

List<ChatMessage> history =
[
    new(ChatRole.System, """
        You are a research agent. Your goal is to thoroughly research the given topic using
        the web_search tool, save key findings with add_note, then produce a final summary.

        Workflow:
        1. Search the web 2-4 times with varied queries to cover different angles.
        2. After each search, save the most important facts using add_note.
        3. When you have enough information, call read_notes to review everything.
        4. Finally, write a comprehensive summary in markdown with sections and citations.

        Be thorough but concise. Always ground your summary in the search results.
        """),
    new(ChatRole.User, $"Research the following topic and provide a summary:\n\n{topic}")
];

// --- Agent loop ---

const int maxIterations = 20;
for (var i = 0; i < maxIterations; i++)
{
    var response = await client.GetResponseAsync(history, chatOptions);

    // Append all response messages to history
    foreach (var msg in response.Messages)
        history.Add(msg);

    // Check if the model is done (no more tool calls)
    bool hasToolCalls = response.Messages
        .Any(m => m.Contents.OfType<FunctionCallContent>().Any());

    if (!hasToolCalls)
    {
        // Final answer
        var answer = response.Messages
            .LastOrDefault(m => m.Role == ChatRole.Assistant && m.Text is not null);
        Console.WriteLine("\n═══════════════════════════════════════");
        Console.WriteLine("📋 RESEARCH SUMMARY");
        Console.WriteLine("═══════════════════════════════════════\n");
        Console.WriteLine(answer?.Text ?? "(no summary produced)");
        Console.WriteLine($"\n📊 Notes collected: {notebook.GetAll().Count}");
        break;
    }
}

// --- Helpers ---

static string PromptForTopic()
{
    Console.Write("Enter a research topic: ");
    var input = Console.ReadLine()?.Trim();
    return string.IsNullOrEmpty(input)
        ? "Recent advances in quantum computing 2025-2026"
        : input;
}

// --- Supporting classes ---

sealed class Notebook
{
    private readonly List<string> _notes = [];
    public void Add(string note) => _notes.Add(note);
    public List<string> GetAll() => [.. _notes];
}

static class WebSearcher
{
    private static readonly HttpClient Http = new();

    public static async Task<string> SearchAsync(string query)
    {
        // Uses the free DuckDuckGo instant-answer API as a lightweight search source.
        var encoded = Uri.EscapeDataString(query);
        var url = $"https://api.duckduckgo.com/?q={encoded}&format=json&no_html=1&skip_disambig=1";

        try
        {
            var json = await Http.GetStringAsync(url);
            var doc = System.Text.Json.JsonDocument.Parse(json);
            var root = doc.RootElement;

            var results = new List<string>();

            // Abstract / summary
            var abs = root.GetProperty("Abstract").GetString();
            if (!string.IsNullOrWhiteSpace(abs))
                results.Add($"Summary: {abs} (source: {root.GetProperty("AbstractSource").GetString()})");

            // Related topics
            if (root.TryGetProperty("RelatedTopics", out var topics))
            {
                foreach (var item in topics.EnumerateArray().Take(5))
                {
                    var text = item.TryGetProperty("Text", out var t) ? t.GetString() : null;
                    if (!string.IsNullOrWhiteSpace(text))
                        results.Add(text);
                }
            }

            // Answer box
            var answer = root.GetProperty("Answer").GetString();
            if (!string.IsNullOrWhiteSpace(answer))
                results.Add($"Answer: {answer}");

            return results.Count > 0
                ? string.Join("\n\n", results)
                : $"No detailed results found for \"{query}\". Try a different query.";
        }
        catch (Exception ex)
        {
            return $"Search failed: {ex.Message}. Try a different query.";
        }
    }
}

